mapper.select:
SELECT *
FROM ts_story_info
WHERE user_id = #{query.userId}
  AND is_deleted = 0

    AND (
        title LIKE CONCAT('%', #{query.keyword}, '%')
        OR story_intro LIKE CONCAT('%', #{query.keyword}, '%')
    )


    AND status = #{query.status}


    AND is_public = #{query.isPublic}


    AND story_mode = #{query.storyMode}

ORDER BY updated_at DESC, id DESC
